  ('dietitian-moex-08224', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '若一分子的NADH及FADH 經電子傳遞鏈完全氧化可分別產生3分子及2分子ATP，則在腦細胞中一 2 分子葡萄糖完全氧化可產生多少分子ATP？', '["30", "32", "36", "38"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08225', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '某酵素有四種抑制物，compound A、compound B、compound C及compound D，其抑制物結合之解離常 數（Ki）分別為1×10-2M、7×10-11M、5×10-9M、3×10-5M，則那一抑制物是此酵素之最佳抑制物？', '["compound A", "compound B", "compound C", "compound D"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
